# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SecureSQSPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        """
        Initialize SQS publisher with secure configurations
        """
        try:
            # Use IAM roles for authentication when possible
            if 'AWS_ACCESS_KEY_ID' not in os.environ and 'AWS_SECRET_ACCESS_KEY' not in os.environ:
                # Assume IAM role is available
                self.sqs_client = boto3.client('sqs', region_name=region_name)
            else:
                # Use explicit credentials
                self.sqs_client = boto3.client(
                    'sqs',
                    region_name=region_name,
                    aws_access_key_id=os.environ.get('AWS_ACCESS_KEY_ID'),
                    aws_secret_access_key=os.environ.get('AWS_SECRET_ACCESS_KEY')
                )
            
            self.queue_url = queue_url
            self.region_name = region_name
            
        except Exception as e:
            logger.error(f"Failed to initialize SQS client: {str(e)}")
            raise

    def _validate_pii_data(self, data: Dict[str, Any]) -> bool:
        """
        Validate PII data before sending
        """
        required_fields = ['email', 'phone', 'address']
        for field in required_fields:
            if field not in data or not data[field]:
                logger.warning(f"Missing required PII field: {field}")
                return False
        return True

    def _sanitize_message(self, message_data: Dict[str, Any]) -> Dict[str, Any]:
        """
        Sanitize message data to remove any potentially harmful content
        """
        sanitized = {}
        for key, value in message_data.items():
            if isinstance(value, str):
                # Remove potentially dangerous characters
                sanitized[key] = value.replace('\x00', '').strip()
            else:
                sanitized[key] = value
        return sanitized

    def publish_user_data(self, user_data: Dict[str, Any]) -> bool:
        """
        Publish user data to SQS queue with PII handling
        """
        try:
            # Validate PII data
            if not self._validate_pii_data(user_data):
                logger.error("Invalid PII data provided")
                return False

            # Sanitize message
            sanitized_data = self._sanitize_message(user_data)

            # Prepare message
            message_body = json.dumps({
                'user_data': sanitized_data,
                'timestamp': self._get_timestamp(),
                'source': 'secure_publisher'
            })

            # Send message to SQS
            response = self.sqs_client.send_message(
                QueueUrl=self.queue_url,
                Message=message_body,
                MessageAttributes={
                    'SourceType': {
                        'StringValue': 'SecurePublisher',
                        'DataType': 'String'
                    },
                    'PIIHandling': {
                        'StringValue': 'Processed',
                        'DataType': 'String'
                    }
                }
            )

            logger.info(f"Message sent successfully. MessageId: {response['MessageId']}")
            return True

        except ClientError as e:
            logger.error(f"SQS ClientError: {str(e)}")
            return False
        except Exception as e:
            logger.error(f"Unexpected error while publishing message: {str(e)}")
            return False

    def _get_timestamp(self) -> str:
        """
        Get current timestamp
        """
        from datetime import datetime
        return datetime.utcnow().isoformat() + 'Z'

